    case newChallenge = "새로운 도전"
    case noDelays = "미루지 않음"
    case focusAndFlow = "집중과 몰입"
    case sawItThrough = "끝까지 해냄"
    case learningAndGrowth = "배움과 성장"
    // 연결
    case warmWords = "따뜻한 말 한마디"
    case familyTime = "가족과의 시간"
    case expressedGratitude = "고마움 표현"
    case gratitude = "감사"
    case smallHelp = "작은 도움"
    // 자기돌봄
    case restAndRecharge = "휴식과 재충전"
    case tidyingUp = "정리정돈"
    case exercise = "운동"
    case goodSleep = "충분한 수면"
    case myTime = "나만의 시간"

    var label: String { rawValue }

    var section: DiscoverySection {
        switch self {
        case .newChallenge, .noDelays, .focusAndFlow, .sawItThrough, .learningAndGrowth:
