import Foundation

extension Date {
    var startOfMonth: Date {
        let components = Calendar.current.dateComponents([.year, .month], from: self)
        return Calendar.current.date(from: components)!
    }

    var endOfMonth: Date {
        var components = DateComponents()
        components.month = 1
        components.second = -1
        return Calendar.current.date(byAdding: components, to: startOfMonth)!
    }

    var daysInMonth: Int {
        Calendar.current.range(of: .day, in: .month, for: self)!.count
    }

    /// 월요일 시작 기준 첫 번째 날의 오프셋 (월=0, 화=1, ..., 일=6)
    var firstWeekdayOffset: Int {
        let weekday = Calendar.current.component(.weekday, from: startOfMonth)
        // Calendar.weekday: 1=일, 2=월, ..., 7=토
        return (weekday + 5) % 7
    }

    /// 달력 그리드에 필요한 총 셀 수 (7의 배수)
    var calendarGridCount: Int {
        let total = firstWeekdayOffset + daysInMonth
        return total % 7 == 0 ? total : total + (7 - total % 7)
    }

    var monthYear: String {
        let formatter = DateFormatter()
        formatter.dateFormat = "yyyy년 M월"
        return formatter.string(from: self)
    }

    func isSameDay(as other: Date) -> Bool {
        Calendar.current.isDate(self, inSameDayAs: other)
    }
}

