import SwiftUI

// MARK: - 미기록 날 UI 옵션 프리뷰
// 확인 후 삭제해도 됩니다

private struct MissedDayPreview: View {
    // 5월 색상으로 테스트
    let colors: [Color] = [
        Color(hex: "F8D8F5"),
        Color(hex: "E76767"),
        Color(hex: "E76767"),
        Color(hex: "FFE6FD"),
        Color(hex: "E76767"),
        Color(hex: "E76767"),
        Color(hex: "F8D8F5"),
    ]

    var body: some View {
        ScrollView {
            VStack(alignment: .leading, spacing: 32) {

                // 기준: 기록된 날
                option(title: "기록됨 (기준)") { color in
                    Circle().fill(color)
                }

                // A: 낮은 opacity
                option(title: "A — 같은 색 opacity 20%") { color in
                    Circle().fill(color.opacity(0.2))
                }

                // B: 작은 원
                option(title: "B — 작은 원 (65% 크기) + 같은 색") { color in
                    Circle().fill(color)
                        .frame(width: 28 * 0.65, height: 28 * 0.65)
                }

                // C: 그레이스케일
                option(title: "C — 그레이스케일") { color in
                    Circle().fill(color.grayscale)
                }

                // D: 테두리만
                option(title: "D — 테두리(stroke)만") { color in
                    Circle().strokeBorder(color, lineWidth: 1.5)
                }

                // E: 색 + 얇은 빗금 (X)
                option(title: "E — 연한 색 + X 표시") { color in
                    ZStack {
                        Circle().fill(color.opacity(0.15))
                        Image(systemName: "xmark")
                            .font(.system(size: 10, weight: .light))
                            .foregroundColor(color.opacity(0.5))
                    }
                }

                // F: 작은 원 + 테두리
                option(title: "F — 작은 원 + 테두리") { color in
                    ZStack {
                        Circle().strokeBorder(color.opacity(0.4), lineWidth: 1.5)
                        Circle().fill(color.opacity(0.15))
                    }
                }
            }
            .padding()
        }
        .background(Color(hex: "F5F5F5"))
    }

    func option(title: String, cell: @escaping (Color) -> some View) -> some View {
        VStack(alignment: .leading, spacing: 8) {
            Text(title)
                .font(.caption)
                .foregroundColor(.secondary)
            HStack(spacing: 6) {
                ForEach(colors.indices, id: \.self) { i in
                    ZStack {
                        cell(colors[i])
                            .frame(width: 28, height: 28)
                    }
                    .frame(width: 28, height: 28)
                }
            }
        }
    }
}

private extension Color {
    var grayscale: Color {
        // UIColor로 변환해서 채도 제거
        let uiColor = UIColor(self)
        var white: CGFloat = 0
        uiColor.getWhite(&white, alpha: nil)
        return Color(white: Double(white))
    }
}

#Preview {
    MissedDayPreview()
}

